INSERT INTO `v1_ebf818d8910aa4140c2b5fe10ed5af12c75b44431a898f535c3d3f877c3fad56` VALUES ("【加速】", "ＴＰ回復や行動速度アップにより、キャラのスキルやユニオンバーストの発動数が増加する\n", "加速", 1);
INSERT INTO `v1_ebf818d8910aa4140c2b5fe10ed5af12c75b44431a898f535c3d3f877c3fad56` VALUES ("【弱体】", "敵に継続ダメージ系状態異常や弱体効果を付与し、敵を弱体化させる\n", "弱体", 2);
INSERT INTO `v1_ebf818d8910aa4140c2b5fe10ed5af12c75b44431a898f535c3d3f877c3fad56` VALUES ("【会心】", "クリティカルや通常攻撃強化により、攻撃性能を強化する\n", "会心", 3);
INSERT INTO `v1_ebf818d8910aa4140c2b5fe10ed5af12c75b44431a898f535c3d3f877c3fad56` VALUES ("【強化】", "攻撃力や防御力アップのバフ効果を用いて、キャラを強化する\n", "強化", 4);
INSERT INTO `v1_ebf818d8910aa4140c2b5fe10ed5af12c75b44431a898f535c3d3f877c3fad56` VALUES ("【守備】", "ＨＰアップやバリア展開により、耐久性能を強化する\n", "守備", 5);
